class Solution:
    def solve(self, operations):
        heap = {
            0: [1]
        }
        for op, x in operations:
            if op == 'insert':
                tree = [x]
                parent = heap[0]
                child = tree[-1]
                heap[0].append(child)
                heap[child] = [parent, child]
            elif op == 'delete':
                node = x
                while node in heap:
                    child = heap[node][0]
                    parent = heap[node][1]
                    heap.pop(node)
                    heap[parent][0] = child
                    heap[child].pop(1)
                    heap[child].insert(0, parent)
                    node = child
        return True

